var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"벌써... 얼마나 많은 수호자들을 혼자서 쓰러트린 거지?","JPN":"これで……何人の守護者を一人で倒した？","ENG":"Already... how many Guardians has she taken down on her own?","TWN":"你已經……自己擊敗多少守護者了？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"얼마나 쓰러트리건 탐미엘은 멈추지 않겠지. 그녀가 가진 권능엔 한계가 없으니.","JPN":"何人倒そうと、タミエルは止まらないだろう。彼女の権能に限界はないからね。","ENG":"No matter how many she defeats, Tammiel will not stop. There is no limit to the power she wields.","TWN":"無論擊敗多少，塔米爾都不會停止。她的權能沒有極限。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"하나가 쓰러지면 둘을, 둘이 쓰러지면 넷을, 넷이 쓰러지면 여덟을.","JPN":"1人が倒れたら2人を、2人が倒れたら4人を、4人が倒れたら8人を。","ENG":"If one falls, then two. If two fall, then four. If four fall, then eight.","TWN":"一個倒下，就補上兩個；兩個倒下，就補上四個；四個倒下，就補上八個。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"그 순환에는 끝이 존재하지 않을 거야. 네가 멋대로 되살린 녀석들이 전부 사라질 때까지.","JPN":"その循環に終わりはないわ。あなたが勝手に蘇らせたやつらが全員消えるまで。","ENG":"That cycle will never end. Not until every one of those you revived disappears.","TWN":"那個循環不會結束，直到你擅自復活的那些傢伙全部消失為止。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"그들의 죽음은 탐미엘이란 신이 멋대로 정한 운명일 뿐.","JPN":"彼らの死はタミエルという神が勝手に決めた運命にすぎません。","ENG":"Their deaths are nothing more than a fate arbitrarily decided by the god called Tammiel.","TWN":"他們的死亡，只是塔米爾這個神隨意決定的命運。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ANAPILIS_CA_SCYTHE_IN_TRAILER_10"},{"id":"L10_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"더는 이들이 당신의 규칙에 놀아나게 두지 않겠어요.","JPN":"もう彼らがあなたのルールに踊らされないようにします。","ENG":"I will not allow them to remain at the mercy of your rules any longer.","TWN":"我不會再讓他們任由你的規則擺布。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ANAPILIS_CA_SCYTHE_IN_TRAILER_11"},{"id":"L13_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"...하지만 탐미엘을 이길 방법도 없는 게 사실이다.","JPN":"……だが、タミエルに勝つ方法がないのも事実だ。","ENG":"...But it's also true that there's no way to defeat Tammiel.","TWN":"……但是，無法擊敗塔米爾也是事實。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"제아무리 강한 힘을 가졌다고 해도, 규칙에 얽매이지 않은 존재를 꺾을 순 없어.","JPN":"いくら強い力を持っているとしても、ルールに縛られない存在に勝つことはできない。","ENG":"No matter how great your power is, you cannot defeat a being that is not bound by rules.","TWN":"無論再強大的力量，也無法打破不受規則束縛的存在。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 말대로 우린 탐미엘을 막을 수 없어.","JPN":"君の言う通り、我々はタミエルを止められない。","ENG":"As you said, we cannot stop Tammiel.","TWN":"如你所說，我們無法阻止塔米爾。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세피로트 나무의 권한으로 자신만의 규칙을 만들고, 그 틀 안에 있는 것들을 모두 운명이라는 실로 조종해왔으니까.","JPN":"彼女はセフィロトの権限で自分だけのルールを作り、その中にあるものをすべて運命という糸で操ってきた。","ENG":"With the authority of the Tree of Sephiroth, she created rules of her own and has manipulated everything within them using the threads of fate.","TWN":"她透過生命樹的權限創造自己的規則，並在其中操控所有命運。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그녀는 지금 끝나지 않은 클리포트 게임 안에서 힘을 행사하고 있네. 탐미엘이라는 최초의 신, 클리포트의 정점에 있는 마왕으로서 말이야.","JPN":"だが彼女は今、終わっていないクリフォトゲームの中で力を行使している。タミエルという最初の神、クリフォトの頂点に立つ魔王として。","ENG":"However, she is currently exercising her power within the still-unfinished Qliphoth Game as Tammiel, the first god and the Demon Lord at the apex of the Qliphoth.","TWN":"但現在她作為名為塔米爾的最初之神，逆卡巴拉頂點的魔王，在尚未結束的逆卡巴拉遊戲中行使力量。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CA_ANAPILIS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"...들리시나요?","JPN":"……聞こえていますか？","ENG":"...Can you hear me?","TWN":"……你聽見了嗎？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_18"},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어떻게 된 거지?","JPN":"どうなってるの？","ENG":"What's going on?","TWN":"這是怎麼回事？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"분명, 언니를... 봤던 것 같은데.","JPN":"確か、姉さんを……見た気がするけど。","ENG":"I'm sure I just... saw my sister.","TWN":"我明明……看到過姐姐……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"탐미엘, 그녀가 인과율의 흐름을 잠시 멈추고 사람들을 모두 제거하기 위해 강림했어요.","JPN":"タミエル、彼女が因果律の流れを一時的に止めて、人々をすべて排除するために降臨しました。","ENG":"Tammiel has descended, temporarily halting the flow of causality in order to eliminate everyone.","TWN":"塔米爾她暫時停止了因果率的流動，為了抹除所有人而降臨。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"지금 그들에겐, 당신의 도움이 필요해요.","JPN":"今彼らにはあなたの助けが必要です。","ENG":"Right now, they need your help.","TWN":"現在，他們需要你的幫助。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내... 도움이라고?","JPN":"私の……助け？","ENG":"My... help?","TWN":"我的……幫助？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 알잖아. 난 더 이상 늑대가 아니야.","JPN":"でも知ってるでしょ。私はもうオオカミじゃないんだ。","ENG":"But you know. I'm no longer the Wolf.","TWN":"但你也知道，我已經不是那隻狼了。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아무것도 아닌 내가... 뭘 할 수 있겠어?","JPN":"何者でもない私に……何ができるというの？","ENG":"Someone like me... what could I possibly do?","TWN":"什麼都不是的我……能做什麼？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"맞아요. 당신은 아무것도 아니죠.","JPN":"そう。あなたは何者でもない。","ENG":"That's right. You are nothing.","TWN":"沒錯。你什麼都不是。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"당신은 늑대라는 운명의 주박을 벗어던진- 탐미엘이 정한 그 규칙에도 얽매이지 않는 존재.","JPN":"あなたはオオカミという運命の呪縛を脱ぎ捨てた……タミエルが決めたルールにも縛られない存在。","ENG":"You are someone who cast off the shackles of the fate called the Wolf. Someone no longer bound by the rules Tammiel set.","TWN":"你已經擺脫了狼這個命運的枷鎖—不受塔米爾既定規則束縛的存在。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"그렇기 때문에, 당신만이 그녀를 막을 수 있어요.","JPN":"だから、あなただけが、彼女を止められます。","ENG":"That is why only you can stop her.","TWN":"正因如此，只有你能阻止她。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"제가 아닌, 운명으로 고통받는 모든 이들을 위해서... 이 운명을 쥐고 그녀와 맞서주세요.","JPN":"私ではなく、運命に苦しまされるすべての者のために……この運命を握って、彼女に立ち向かってください。","ENG":"Not for my sake, but for all those suffering under the weight of fate... please take hold of this fate and stand against her.","TWN":"不是我，而是為了那些被命運折磨的人……請握緊這個命運，與她對抗。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀가 황금나무의 운명을 받아들이고, 세계 그 자체로서 의지를 갖기를 택한 건... 단순히 죽은 자들을 살리고 위해서가 아닌 거야.","JPN":"彼女が黄金の木の運命を受け入れ、世界そのものとしての意志を持つことを選んだのは、ただ死んだ者を蘇らせたかったからではないだろう。","ENG":"The reason she accepted the fate of the Golden Tree and chose to become the will of the world itself... was not simply because she wanted to revive the dead.","TWN":"她選擇接受黃金樹的命運，成為世界本身的意志…… 不只單純是為了讓死者復活。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"종말의 위협으로부터 세계를 지키는 존재...","JPN":"終末の脅威から世界を守る存在……","ENG":"A being that protects the world from the threat of its end...","TWN":"為了從末日的威脅中守護世界……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕을 꺾기 위해 세계가 선택하는 최후의 보루...","JPN":"魔王を倒すために世界が選ぶ、最後の砦……","ENG":"The final stronghold the world chooses to defeat the Demon Lord...","TWN":"為了擊敗魔王，世界所選擇的最後防線……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L47_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"유미나?!","JPN":"ヤナギ・ミナ！？","ENG":"Yoo Mina?!","TWN":"劉米娜？！"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"탐미엘...!","JPN":"タミエル……！","ENG":"Tammiel...!","TWN":"塔米爾……！"},"stage":{"bg":"SKY_RED","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕 탐미엘을 쓰러트릴 대적자를 만들고자 한 거지.","JPN":"魔王タミエルを倒す敵対者を生み出そうとしたのさ。","ENG":"She intended to create an Antagonist who could defeat the Demon Lord Tammiel.","TWN":"你們想創造一個能擊敗魔王塔米爾的對手。"},"stage":{"bg":"BLACK","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};